} catch (KafkaException e) {
  producer.abortTransaction();
}

import { Kafka } from 'kafkajs';

const kafka = new Kafka({ brokers: ['localhost:9092'] });
const consumer = kafka.consumer({ groupId: 'inventory-service' });

await consumer.connect();
await consumer.subscribe({ topic: 'product-updates', fromBeginning: false });

await consumer.run({
  eachMessage: async ({ topic, partition, message }) => {
    // Process first, then commit — at-least-once semantics
    await processUpdate(message.value?.toString());
    await consumer.commitOffsets([{
      topic,
      partition,
      offset: (BigInt(message.offset) + 1n).toString(),
    }]);
  },
});

nc, _ := nats.Connect(nats.DefaultURL)
js, _ := nc.JetStream()

// Equivalent to Kafka CreateTopic — stream binds subject wildcards
js.AddStream(&nats.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
    Replicas: 3,
})

// Durable = Kafka consumer group; AckExplicit = auto.commit false
js.Subscribe("orders.>", func(msg *nats.Msg) {
    process(msg.Data)
    msg.Ack() // skipping Ack → redelivery after AckWait
}, nats.Durable("order-processor"), nats.AckExplicit())

import { Queue, Worker, FlowProducer } from 'bullmq';

const queue = new Queue('reports', { connection: { host: 'localhost', port: 6379 } });

// Priority job — lower number = higher priority
await queue.add('generate-pdf', { userId: 42 }, { priority: 1 });

// Rate-limited worker: max 5 jobs per 10 seconds
const worker = new Worker('reports', async job => {
  console.log('Processing', job.name, job.data);
}, { limiter: { max: 5, duration: 10_000 }, connection: { host: 'localhost', port: 6379 } });

// Repeatable job via cron
await queue.add('weekly-digest', {}, { repeat: { pattern: '0 9 * * MON' } });

// Parent/child dependency flow
const flow = new FlowProducer({ connection: { host: 'localhost', port: 6379 } });
await flow.add({ name: 'send-report', queueName: 'reports', data: {},
  children: [{ name: 'fetch-data', queueName: 'reports', data: { source: 'db' } }] });

// Fetch consumer group lag per partition using AdminClient
try (AdminClient admin = AdminClient.create(props)) {
    Map<TopicPartition, OffsetAndMetadata> committed =
        admin.listConsumerGroupOffsets("my-group")
             .partitionsToOffsetAndMetadata().get();

    Map<TopicPartition, OffsetSpec> latestReq = committed.keySet().stream()
        .collect(Collectors.toMap(tp -> tp, tp -> OffsetSpec.latest()));

    Map<TopicPartition, ListOffsetsResult.ListOffsetsResultInfo> endOffsets =
        admin.listOffsets(latestReq).all().get();

    committed.forEach((tp, meta) -> {
        long lag = endOffsets.get(tp).offset() - meta.offset();
        System.out.printf("Partition %s lag: %d%n", tp, lag);
    });
}

const { Kafka } = require('kafkajs');

const kafka = new Kafka({ clientId: 'app', brokers: ['broker:9092'] });

const consumer = kafka.consumer({
  groupId: 'orders-group',
  sessionTimeout: 30000,
  rebalanceTimeout: 60000,
  maxWaitTimeInMs: 5000,
});

await consumer.connect();
await consumer.subscribe({ topic: 'orders', fromBeginning: false });

// CooperativeStickyAssignor requires kafkajs >= 2.x
// Set partitionAssigners in kafka-configs for broker-side
await consumer.run({
  partitionsConsumedConcurrently: 3,
  eachMessage: async ({ topic, partition, message }) => {
    console.log(`[${partition}] ${message.value?.toString()}`);
  },
});
